function Dashboard() {

  const posts = [
    {
      id:1,
      title:"My First Blog"
    },
    {
      id:2,
      title:"React Guide"
    }
  ];

  return (
    <div className="container">

      <h1>My Posts</h1>

      {posts.map(post => (

        <div className="dashboard-card" key={post.id}>

          <h3>{post.title}</h3>

          <div>
            <button>✏ Edit</button>
            <button>🗑 Delete</button>
          </div>

        </div>

      ))}

    </div>
  );
}

export default Dashboard;
